example.code:
class SQLAlchemyUserRepository(UserRepository):
    """Implements the domain interface. Domain code never imports this class."""

    def __init__(self, session: AsyncSession):
        self._session = session

    async def find_by_id(self, user_id: UUID) -> Optional[User]:
        result = await self._session.execute(
            select(UserModel).where(UserModel.id == user_id)
        )
        model = result.scalar_one_or_none()
        return self._to_entity(model) if model else None

    async def save(self, user: User) -> None:
        model = self._to_model(user)
        self._session.add(model)

    def _to_entity(self, model: "UserModel") -> User:
        return User(
            id=model.id, name=model.name, email=Email(model.email),
            role=model.role, is_active=model.is_active, created_at=model.created_at,
        )

    def _to_model(self, entity: User) -> "UserModel":
        return UserModel(
            id=entity.id, name=entity.name, email=entity.email.value,
            role=entity.role, is_active=entity.is_active, created_at=entity.created_at,
        )
